1	import { useCallback, useEffect, useMemo, useRef, useState } from 'react';
2	import {
3	  Keyboard,
4	  Modal,
5	  Platform,
6	  Pressable,
7	  RefreshControl,
8	  SafeAreaView,
9	  ScrollView,
10	  StyleSheet,
11	  Text,
12	  TextInput,
13	  View,
14	} from 'react-native';
15	import { BottomSheet } from '@/components/primitives/BottomSheet';
16	import { ButtonPrimary, ButtonSecondary } from '@/components/primitives/Button';
17	import { StatusPill, type StatusPillStatus } from '@/components/primitives/StatusPill';
18	import { SkeletonCard } from '@/components/primitives/SkeletonCard';
19	import { useToast } from '@/components/primitives/Toast';
20	import { colors, radii, shadows, spacing } from '@/design/tokens';
21	import { fontFamilies, textStyles } from '@/design/typography';
22	import { useAuth } from '@/lib/auth';
23	import { getCachedToken } from '@/lib/storage';
24	import { supabase } from '@/lib/supabase';
25	import { formatRelativeTime } from '@/lib/time';
26	import type { Database } from '@/types/supabase';
27	
28	// US-056 — Lister Inbox, Applications sub-tab. Calls the
29	// `list_my_applications_as_lister` SECURITY DEFINER RPC (companion migration
30	// `us_056_list_my_applications_as_lister_rpc`) which joins applications →
31	// listings → users → creator_profiles → social_links under an explicit
32	// `listings.lister_id = current_user_id()` ownership gate and returns one
33	// flat row per application — creator username + platform handles + follower
34	// counts + IG avg views + pitch preview. Same list-my-rows pattern as
35	// US-043 / US-054 (Codebase Pattern #118).
36	//
37	// Segments: Pending / Approved / Rejected per AC. The RPC already excludes
38	// withdrawn + cancelled_listing_edit + cancelled_listing_closed — those are
39	// creator-initiated or cascade-driven cancellations that don't require
40	// lister review. They surface on the campaign-scoped detail screen
41	// (US-057+), not the inbox.
42	//
43	// Grouping: per docs/design.md §3.2 the inbox groups rows by campaign with
44	// inline SectionHeader separators. The RPC returns rows in
45	// `created_at desc`, so within each group rows remain recency-ordered; the
46	// group order is driven by the most-recent application within each group.
47	//
48	// Realtime INSERT subscription: applications is already in the
49	// supabase_realtime publication (US-044). We subscribe with no client
50	// filter because applications has no lister_id column — the
51	// `applications_lister_read` RLS policy is the join-through-listings
52	// security boundary (Codebase Pattern #123). Because the raw INSERT
53	// payload lacks the joined creator + platform metrics, on each insert we
54	// re-run the RPC rather than patching locally. A toast ("New application
55	// received", info variant) gives the lister an in-app cue.
56	//
57	// US-057 — pending rows are tappable; tap opens a ReviewApplicationSheet
58	// (bottom sheet, design.md §3.3). The sheet shows full creator metrics +
59	// pitch and exposes an optional "Note" field plus Approve / Reject
60	// buttons. Both buttons POST to the `decide-application` edge function.
61	//
62	// Approve flow:
63	//   1. POST { action:'approve', application_id, decision_note? }
64	//   2a. 200 {ok:true} → toast "Application approved", refresh list, close
65	//   2b. 200 {ok:false, drift:[...]} → close the review sheet and open the
66	//       OverrideEligibilityDialog (centered modal, design.md §5.2 — "modals
67	//       except confirmations are bottom sheets" + Codebase Pattern #129).
68	//   2c. Override "Approve anyway" → POST again with override_ineligible:true,
69	//       which skips eligibility AND skips the version pin per the
70	//       force-approve semantics in the RPC's docblock.
71	//
72	// Reject flow:
73	//   1. POST { action:'reject', application_id, decision_note? }
74	//   2. Toast "Application rejected", refresh list, close.
75	//
76	// LISTING_VERSION_CHANGED — surfaces a "Listing was updated" toast and
77	// re-loads. Same backstop as the creator-side ApplySheet.
78	
79	type ApplicationStatus = Database['public']['Enums']['application_status'];
80	type Segment = 'pending' | 'approved' | 'rejected';
81	type Row = Database['public']['Functions']['list_my_applications_as_lister']['Returns'][number];
82	
83	// Compile-time exhaustive mapping: if a new enum value is added the
84	// compiler flags the missing bucket (Codebase Pattern #121). The three
85	// enum values the RPC filters out are intentionally absent — they cannot
86	// reach this screen.
87	const STATUS_BUCKET: Record<
88	  Exclude<
89	    ApplicationStatus,
90	    'withdrawn' | 'cancelled_listing_edit' | 'cancelled_listing_closed'
91	  >,
92	  Segment
93	> = {
94	  pending: 'pending',
95	  approved: 'approved',
96	  rejected: 'rejected',
97	};
98	
99	const SEGMENTS: readonly { key: Segment; label: string }[] = [
100	  { key: 'pending', label: 'Pending' },
101	  { key: 'approved', label: 'Approved' },
102	  { key: 'rejected', label: 'Rejected' },
103	];
104	
105	type SegmentControlProps = {
106	  active: Segment;
107	  counts: Record<Segment, number>;
108	  onChange: (next: Segment) => void;
109	};
110	
111	function SegmentControl({ active, counts, onChange }: SegmentControlProps) {
112	  return (
113	    <View style={styles.segmentRow} accessibilityRole="tablist">
114	      {SEGMENTS.map((s) => (
115	        <SegmentButton
116	          key={s.key}
117	          label={`${s.label} (${counts[s.key]})`}
118	          selected={active === s.key}
119	          onPress={() => onChange(s.key)}
120	          testID={`segment-${s.key}`}
121	        />
122	      ))}
123	    </View>
124	  );
125	}
126	
127	type SegmentButtonProps = {
128	  label: string;
129	  selected: boolean;
130	  onPress: () => void;
131	  testID?: string;
132	};
133	
134	function SegmentButton({ label, selected, onPress, testID }: SegmentButtonProps) {
135	  const bg = selected ? colors.primarySoft : colors.surface;
136	  const textColor = selected ? colors.primaryDeep : colors.ink;
137	  return (
138	    <Pressable
139	      onPress={onPress}
140	      accessibilityRole="tab"
141	      accessibilityState={{ selected }}
142	      accessibilityLabel={label}
143	      style={[styles.segment, { backgroundColor: bg }, shadows.hard]}
144	      testID={testID}
145	    >
146	      <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
147	        {label}
148	      </Text>
149	    </Pressable>
150	  );
151	}
152	
153	// SectionHeader per docs/design.md §6 — kept inline until a second consumer
154	// shows up. The `══════ Label ══════` visual uses horizontal rules bracketing
155	// the title; a single flex row with 2-px borders keeps it token-friendly.
156	function SectionHeader({ title }: { title: string }) {
157	  return (
158	    <View style={styles.sectionHeaderRow} accessibilityRole="header">
159	      <View style={styles.sectionRule} />
160	      <Text
161	        style={[textStyles.micro, { color: colors.ink }]}
162	        allowFontScaling={false}
163	        numberOfLines={1}
164	      >
165	        {title}
166	      </Text>
167	      <View style={styles.sectionRule} />
168	    </View>
169	  );
170	}
171	
172	function bucketFor(status: ApplicationStatus): Segment | null {
173	  if (status === 'withdrawn') return null;
174	  if (status === 'cancelled_listing_edit') return null;
175	  if (status === 'cancelled_listing_closed') return null;
176	  return STATUS_BUCKET[status];
177	}
178	
179	type Drift = {
180	  metric: string;
181	  platform: 'tiktok' | 'instagram' | null;
182	  required: number | boolean;
183	  actual: number | boolean | null;
184	};
185	
186	type DecideResponse = {
187	  ok?: boolean;
188	  status?: string;
189	  decided_at?: string;
190	  drift?: Drift[];
191	};
192	
193	type DecideErrorBody = {
194	  error?: string;
195	  current_version_id?: string;
196	};
197	
198	type OverrideContext = {
199	  row: Row;
200	  drift: Drift[];
201	  decisionNote: string | null;
202	};
203	
204	export default function ListerInboxApplications() {
205	  const { user } = useAuth();
206	  const userId = user?.id ?? null;
207	  const { show: showToast } = useToast();
208	
209	  const [segment, setSegment] = useState<Segment>('pending');
210	  const [rows, setRows] = useState<Row[]>([]);
211	  const [loading, setLoading] = useState(true);
212	  const [refreshing, setRefreshing] = useState(false);
213	  const [error, setError] = useState<string | null>(null);
214	  const [reviewRow, setReviewRow] = useState<Row | null>(null);
215	  const [overrideContext, setOverrideContext] = useState<OverrideContext | null>(null);
216	  const [overrideSubmitting, setOverrideSubmitting] = useState(false);
217	
218	  const load = useCallback(async () => {
219	    if (!userId) return;
220	    setError(null);
221	    const { data, error: rpcError } = await supabase.rpc('list_my_applications_as_lister');
222	    if (rpcError) {
223	      setError("Couldn't load applications.");
224	      setRows([]);
225	    } else {
226	      setRows(data ?? []);
227	    }
228	  }, [userId]);
229	
230	  // Mirror `load` through a ref so the realtime effect can call the latest
231	  // closure without re-subscribing every time `load` re-creates. Same
232	  // pattern as the creator realtime handler (Codebase Pattern #82/#106).
233	  const loadRef = useRef(load);
234	  useEffect(() => {
235	    loadRef.current = load;
236	  }, [load]);
237	
238	  // Toast cooldown: two INSERTs arriving in the same second (e.g. a
239	  // creator applying to two listings back-to-back, or two creators
240	  // racing) would otherwise stack back-to-back toasts. The re-fetch
241	  // itself is idempotent — only the user-facing banner needs dedup.
242	  const lastToastAtRef = useRef(0);
243	  const TOAST_COOLDOWN_MS = 3000;
244	
245	  useEffect(() => {
246	    setLoading(true);
247	    void load().finally(() => setLoading(false));
248	  }, [load]);
249	
250	  const onRefresh = useCallback(async () => {
251	    setRefreshing(true);
252	    await load();
253	    setRefreshing(false);
254	  }, [load]);
255	
256	  // Realtime INSERT subscription. No client-side filter: applications has
257	  // no lister_id column to filter on, and `applications_lister_read` RLS is
258	  // the authoritative boundary (the broker drops any row the caller can't
259	  // SELECT). supabase.realtime.setAuth(token) mirrors the US-036 +
260	  // US-044 pattern for authenticated websockets (Codebase Pattern #105).
261	  useEffect(() => {
262	    if (!userId) return;
263	    const token = getCachedToken();
264	    if (!token) return;
265	    let cancelled = false;
266	    let activeChannel: ReturnType<typeof supabase.channel> | null = null;
267	    void supabase.realtime.setAuth(token).then(() => {
268	      if (cancelled) return;
269	      activeChannel = supabase
270	        .channel(`lister-inbox-applications-${userId}`)
271	        .on(
272	          'postgres_changes',
273	          {
274	            event: 'INSERT',
275	            schema: 'public',
276	            table: 'applications',
277	          },
278	          () => {
279	            void loadRef.current();
280	            const now = Date.now();
281	            if (now - lastToastAtRef.current >= TOAST_COOLDOWN_MS) {
282	              lastToastAtRef.current = now;
283	              showToast({
284	                message: 'New application received',
285	                variant: 'info',
286	              });
287	            }
288	          },
289	        )
290	        .subscribe();
291	    });
292	    return () => {
293	      cancelled = true;
294	      if (activeChannel) void supabase.removeChannel(activeChannel);
295	    };
296	  }, [userId, showToast]);
297	
298	  const byBucket = useMemo(() => {
299	    const map: Record<Segment, Row[]> = { pending: [], approved: [], rejected: [] };
300	    for (const r of rows) {
301	      const b = bucketFor(r.status);
302	      if (b) map[b].push(r);
303	    }
304	    return map;
305	  }, [rows]);
306	
307	  const counts = useMemo<Record<Segment, number>>(
308	    () => ({
309	      pending: byBucket.pending.length,
310	      approved: byBucket.approved.length,
311	      rejected: byBucket.rejected.length,
312	    }),
313	    [byBucket],
314	  );
315	
316	  const grouped = useMemo(() => groupByListing(byBucket[segment]), [byBucket, segment]);
317	  const visibleCount = byBucket[segment].length;
318	
319	  // Centralized decide invocation. Returns the parsed response so the
320	  // caller (review sheet vs override dialog) can branch on drift vs ok.
321	  // Keeping the network call here lets both surfaces share toast/refresh.
322	  const invokeDecide = useCallback(
323	    async (params: {
324	      applicationId: string;
325	      action: 'approve' | 'reject';
326	      decisionNote: string | null;
327	      override: boolean;
328	    }): Promise<
329	      | { kind: 'ok'; status: string }
330	      | { kind: 'drift'; drift: Drift[] }
331	      | { kind: 'failed' }
332	    > => {
333	      try {
334	        const { data, error: invokeError } = await supabase.functions.invoke<DecideResponse>(
335	          'decide-application',
336	          {
337	            body: {
338	              application_id: params.applicationId,
339	              action: params.action,
340	              ...(params.decisionNote ? { decision_note: params.decisionNote } : {}),
341	              ...(params.override ? { override_ineligible: true } : {}),
342	            },
343	          },
344	        );
345	
346	        if (invokeError) {
347	          const body = await readDecideErrorBody(invokeError);
348	          if (body?.error === 'LISTING_VERSION_CHANGED') {
349	            showToast({
350	              message: 'Listing was updated. Refreshing.',
351	              variant: 'info',
352	            });
353	            await load();
354	            return { kind: 'failed' };
355	          }
356	          if (body?.error === 'NOT_PENDING') {
357	            showToast({
358	              message: 'This application was already decided.',
359	              variant: 'info',
360	            });
361	            await load();
362	            return { kind: 'failed' };
363	          }
364	          if (body?.error === 'APPLICATION_NOT_FOUND') {
365	            showToast({
366	              message: 'Application no longer exists.',
367	              variant: 'error',
368	            });
369	            await load();
370	            return { kind: 'failed' };
371	          }
372	          showToast({
373	            message: 'Could not save decision. Try again.',
374	            variant: 'error',
375	          });
376	          return { kind: 'failed' };
377	        }
378	
379	        if (data && data.ok === false && Array.isArray(data.drift)) {
380	          return { kind: 'drift', drift: data.drift };
381	        }
382	        if (data?.ok && data.status) {
383	          return { kind: 'ok', status: data.status };
384	        }
385	        showToast({
386	          message: 'Could not save decision. Try again.',
387	          variant: 'error',
388	        });
389	        return { kind: 'failed' };
390	      } catch (err) {
391	        console.error('decide-application threw', err);
392	        showToast({
393	          message: 'Could not save decision. Try again.',
394	          variant: 'error',
395	        });
396	        return { kind: 'failed' };
397	      }
398	    },
399	    [showToast, load],
400	  );
401	
402	  const handleDecide = useCallback(
403	    async (action: 'approve' | 'reject', decisionNote: string | null) => {
404	      const row = reviewRow;
405	      if (!row) return false;
406	      const result = await invokeDecide({
407	        applicationId: row.application_id,
408	        action,
409	        decisionNote,
410	        override: false,
411	      });
412	      if (result.kind === 'drift') {
413	        setReviewRow(null);
414	        setOverrideContext({ row, drift: result.drift, decisionNote });
415	        return true;
416	      }
417	      if (result.kind === 'ok') {
418	        showToast({
419	          message: action === 'approve' ? 'Application approved' : 'Application rejected',
420	          variant: action === 'approve' ? 'success' : 'info',
421	        });
422	        setReviewRow(null);
423	        await load();
424	        return true;
425	      }
426	      // 'failed' — toast + refresh already handled inside invokeDecide for
427	      // structured errors; close the sheet only when the underlying row is
428	      // no longer pending (load already ran), otherwise leave it open so
429	      // the lister can retry without re-tapping.
430	      return false;
431	    },
432	    [reviewRow, invokeDecide, showToast, load],
433	  );
434	
435	  const handleOverrideConfirm = useCallback(async () => {
436	    const ctx = overrideContext;
437	    if (!ctx || overrideSubmitting) return;
438	    setOverrideSubmitting(true);
439	    const result = await invokeDecide({
440	      applicationId: ctx.row.application_id,
441	      action: 'approve',
442	      decisionNote: ctx.decisionNote,
443	      override: true,
444	    });
445	    setOverrideSubmitting(false);
446	    if (result.kind === 'ok') {
447	      showToast({ message: 'Application approved (override)', variant: 'success' });
448	      setOverrideContext(null);
449	      await load();
450	    } else if (result.kind === 'drift') {
451	      // The RPC skips the eligibility re-check on override, so getting
452	      // drift back here would mean the edge function ignored the override
453	      // flag — keep the dialog open so the user can cancel.
454	      console.warn('override path returned drift unexpectedly');
455	    } else {
456	      setOverrideContext(null);
457	    }
458	  }, [overrideContext, overrideSubmitting, invokeDecide, showToast, load]);
459	
460	  const handleOverrideCancel = useCallback(() => {
461	    if (overrideSubmitting) return;
462	    setOverrideContext(null);
463	  }, [overrideSubmitting]);
464	
465	  return (
466	    <SafeAreaView style={styles.root}>
467	      <ScrollView
468	        contentContainerStyle={styles.scroll}
469	        refreshControl={
470	          <RefreshControl refreshing={refreshing} onRefresh={onRefresh} tintColor={colors.ink} />
471	        }
472	      >
473	        <Text style={[textStyles.display, styles.header]}>Inbox</Text>
474	        <SegmentControl active={segment} counts={counts} onChange={setSegment} />
475	
476	        {loading ? (
477	          <View style={styles.list} testID="applications-loading">
478	            <SkeletonCard />
479	            <SkeletonCard />
480	          </View>
481	        ) : error ? (
482	          <View style={styles.emptyBox}>
483	            <Text style={[textStyles.body, { color: colors.danger }]}>{error}</Text>
484	          </View>
485	        ) : visibleCount === 0 ? (
486	          <View style={styles.emptyBox} testID={`applications-empty-${segment}`}>
487	            <Text style={[textStyles.body, { color: colors.ink70, textAlign: 'center' }]}>
488	              {emptyMessageFor(segment)}
489	            </Text>
490	          </View>
491	        ) : (
492	          <View style={styles.list}>
493	            {grouped.map((group) => (
494	              <View key={group.listingId} style={styles.group}>
495	                <SectionHeader title={group.listingTitle} />
496	                {group.rows.map((row) => (
497	                  <ApplicationInboxRow
498	                    key={row.application_id}
499	                    row={row}
500	                    onPress={
501	                      row.status === 'pending' ? () => setReviewRow(row) : undefined
502	                    }
503	                  />
504	                ))}
505	              </View>
506	            ))}
507	          </View>
508	        )}
509	      </ScrollView>
510	
511	      <ReviewApplicationSheet
512	        row={reviewRow}
513	        onDismiss={() => setReviewRow(null)}
514	        onDecide={handleDecide}
515	      />
516	
517	      <OverrideEligibilityDialog
518	        context={overrideContext}
519	        submitting={overrideSubmitting}
520	        onConfirm={handleOverrideConfirm}
521	        onCancel={handleOverrideCancel}
522	      />
523	    </SafeAreaView>
524	  );
525	}
