540	function groupByListing(rows: Row[]): ListingGroup[] {
541	  const order: string[] = [];
542	  const by = new Map<string, ListingGroup>();
543	  for (const r of rows) {
544	    let g = by.get(r.listing_id);
545	    if (!g) {
546	      g = { listingId: r.listing_id, listingTitle: r.listing_title, rows: [] };
547	      by.set(r.listing_id, g);
548	      order.push(r.listing_id);
549	    }
550	    g.rows.push(r);
551	  }
552	  return order.map((id) => by.get(id)!);
553	}
