674	// Compact thousands formatter: 12_345 → "12.3K", 1_200_000 → "1.2M". Keeps
675	// inbox rows dense and matches the other social-metric callouts on the
676	// discover + detail screens.
677	function formatCount(n: number | null): string {
678	  if (n == null || n < 0) return '—';
679	  if (n < 1_000) return n.toLocaleString('en-US');
680	  if (n < 1_000_000) return `${(n / 1_000).toFixed(n < 10_000 ? 1 : 0)}K`;
681	  return `${(n / 1_000_000).toFixed(n < 10_000_000 ? 1 : 0)}M`;
