698	// US-057 — bottom-sheet review surface (design.md §3.3 — "modals except
699	// confirmations are bottom sheets"). Hosts the same metric block as the
700	// inbox row plus the full pitch (no clamp), an optional Note field, and
701	// Approve / Reject buttons. The sheet is the entry point for the override
702	// flow: when the parent's onDecide returns drift, the parent closes this
703	// sheet and opens the confirmation dialog instead.
704	function ReviewApplicationSheet({ row, onDismiss, onDecide }: ReviewApplicationSheetProps) {
705	  const [note, setNote] = useState('');
706	  const [pendingAction, setPendingAction] = useState<'approve' | 'reject' | null>(null);
707	  const [keyboardHeight, setKeyboardHeight] = useState(0);
708	  // Synchronous lock against rapid double-tap (Pattern #106). useState reads
709	  // in a callback can be stale across back-to-back invocations; a ref is
710	  // set before the first await.
711	  const submittingRef = useRef(false);
712	
713	  // Reset whenever the sheet opens to a new row, so a half-typed note from
714	  // a prior review doesn't leak across application IDs.
715	  useEffect(() => {
716	    if (row) {
717	      setNote('');
718	      setPendingAction(null);
719	      submittingRef.current = false;
720	    }
721	  }, [row?.application_id, row]);
722	
723	  // Same KAV workaround as ApplySheet (Pattern shared with US-042) — RN
724	  // Modal opens its own window so KeyboardAvoidingView can't measure
725	  // correctly. Listen to keyboard events and pad the bottom manually.
726	  useEffect(() => {
727	    const showEvt = Platform.OS === 'ios' ? 'keyboardWillShow' : 'keyboardDidShow';
728	    const hideEvt = Platform.OS === 'ios' ? 'keyboardWillHide' : 'keyboardDidHide';
729	    const showSub = Keyboard.addListener(showEvt, (e) => {
730	      setKeyboardHeight(e.endCoordinates.height);
731	    });
732	    const hideSub = Keyboard.addListener(hideEvt, () => setKeyboardHeight(0));
733	    return () => {
734	      showSub.remove();
735	      hideSub.remove();
736	    };
737	  }, []);
738	
739	  const submit = useCallback(
740	    async (action: 'approve' | 'reject') => {
741	      if (submittingRef.current) return;
742	      submittingRef.current = true;
743	      setPendingAction(action);
744	      const trimmed = note.trim();
745	      const decisionNote = trimmed.length > 0 ? trimmed : null;
746	      try {
747	        await onDecide(action, decisionNote);
748	      } finally {
749	        submittingRef.current = false;
750	        setPendingAction(null);
751	      }
752	    },
753	    [note, onDecide],
754	  );
755	
756	  if (!row) {
757	    return (
758	      <BottomSheet
759	        visible={false}
760	        onDismiss={onDismiss}
761	        accessibilityLabel="Review application"
762	      >
763	        <View />
764	      </BottomSheet>
765	    );
766	  }
767	
768	  const relative = formatRelativeTime(new Date(row.created_at));
769	  const pitch = row.cover_note?.trim() ?? '';
770	  const submitting = pendingAction !== null;
771	
772	  return (
773	    <BottomSheet
774	      visible={row !== null}
775	      onDismiss={submitting ? () => undefined : onDismiss}
776	      snapPoints={[0.85]}
777	      accessibilityLabel="Review application"
778	      testID="review-application-sheet"
779	    >
780	      <ScrollView
781	        contentContainerStyle={[styles.reviewScroll, { paddingBottom: keyboardHeight + spacing.lg }]}
782	        keyboardShouldPersistTaps="handled"
783	      >
784	        <Text style={[textStyles.caption, { color: colors.ink70 }]}>
785	          Review application for
786	        </Text>
787	        <Text style={[textStyles.h1, { color: colors.ink }]} numberOfLines={2}>
788	          {row.listing_title}
789	        </Text>
790	
791	        <View style={styles.reviewSection}>
792	          <Text style={[textStyles.h2, { color: colors.ink }]} numberOfLines={1}>
793	            @{row.creator_username}
794	          </Text>
795	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>Applied {relative}</Text>
796	        </View>
797	
798	        <View style={[styles.reviewSection, styles.metricsBlock]}>
799	          <MetricLine
800	            platform="TikTok"
801	            handle={row.tiktok_handle}
802	            primary={row.tiktok_follower_count}
803	            primaryLabel="followers"
804	            testID="review-metrics-tiktok"
805	          />
806	          <MetricLine
807	            platform="Instagram"
808	            handle={row.instagram_handle}
809	            primary={row.instagram_follower_count}
810	            primaryLabel="followers"
811	            secondary={row.instagram_avg_views_last_10}
812	            secondaryLabel="avg views"
813	            testID="review-metrics-ig"
814	          />
815	        </View>
816	
817	        <View style={styles.reviewSection}>
818	          <Text style={[textStyles.caption, { color: colors.ink70 }]}>Pitch</Text>
819	          <Text style={[textStyles.body, { color: colors.ink }]} testID="review-pitch">
820	            {pitch.length > 0 ? pitch : 'No pitch provided.'}
821	          </Text>
822	        </View>
823	
824	        <View style={styles.reviewSection}>
825	          <View style={styles.labelRow}>
826	            <Text style={[textStyles.caption, { color: colors.ink70 }]}>
827	              Note (optional)
828	            </Text>
829	            <Text
