1003	  }
1004	  const have = typeof d.actual === 'number'
1005	    ? formatCount(d.actual)
1006	    : d.actual === null
1007	    ? '—'
1008	    : String(d.actual);
1009	  return `${head}: need ${formatCount(d.required)}, have ${have}`;
1010	}
