import { useCallback } from 'react';
import {
  Pressable,
  type PressableProps,
  type StyleProp,
  StyleSheet,
  Text,
  type ViewStyle,
} from 'react-native';
import Animated, {
  useAnimatedStyle,
  useSharedValue,
  withSpring,
  type WithSpringConfig,
} from 'react-native-reanimated';
import * as Haptics from 'expo-haptics';
import { colors, radii, shadows, spacing } from '@/design/tokens';
import { SPRING_SOFT, withReducedMotion } from '@/design/motion';
import { useReducedMotion } from '@/design/useReducedMotion';
import { textStyles } from '@/design/typography';

export type ChipProps = {
  label: string;
  active?: boolean;
  onPress?: PressableProps['onPress'];
  disabled?: boolean;
  style?: StyleProp<ViewStyle>;
  accessibilityLabel?: string;
  testID?: string;
};

// Filter chip per docs/design.md §5.1 (horizontal chip row) + §1.2 (primarySoft bg
// when selected). Press = spring.soft scale-to-0.97 per §1.4 line 100; haptic uses
// `selectionAsync` since toggling is a discrete selection change, not an impact.
export function Chip({
  label,
  active = false,
  onPress,
  disabled = false,
  style,
  accessibilityLabel,
  testID,
}: ChipProps) {
  const reduced = useReducedMotion();
  const pressed = useSharedValue(0);
  const interactive = !disabled && !!onPress;

  // Shadow collapses on press by fading shadowOpacity to 0 while the chip
  // translates (3,3) — same compound-prop workaround the Button primitive uses
  // since iOS `shadowOffset` is not animatable through `useAnimatedStyle`.
  const animatedStyle = useAnimatedStyle(() => {
    const v = pressed.value;
    return {
      transform: [
        { translateX: v * 3 },
        { translateY: v * 3 },
        { scale: 1 - v * 0.03 },
      ],
      shadowOpacity: 1 - v,
    };
  });

  const handlePressIn = useCallback(() => {
    if (!interactive) return;
    void Haptics.selectionAsync();
    pressed.value = withSpring(1, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
  }, [interactive, pressed, reduced]);

  const handlePressOut = useCallback(() => {
    if (!interactive) return;
    pressed.value = withSpring(0, withReducedMotion<WithSpringConfig>(SPRING_SOFT, reduced));
  }, [interactive, pressed, reduced]);

  const bg = disabled ? colors.hairline : active ? colors.primarySoft : colors.surface;
  const borderColor = disabled ? colors.ink40 : colors.ink;
  const textColor = disabled ? colors.ink40 : active ? colors.primaryDeep : colors.ink;

  return (
    <Pressable
      onPress={interactive ? onPress : undefined}
      onPressIn={handlePressIn}
      onPressOut={handlePressOut}
      disabled={!interactive}
      accessibilityRole="checkbox"
      accessibilityLabel={accessibilityLabel ?? label}
      accessibilityState={{ checked: active, disabled: !interactive }}
      testID={testID}
    >
      <Animated.View
        style={[
          styles.base,
          { backgroundColor: bg, borderColor },
          disabled ? shadows.none : shadows.hard,
          animatedStyle,
          style,
        ]}
      >
        <Text style={[textStyles.micro, { color: textColor }]} allowFontScaling={false}>
          {label}
        </Text>
      </Animated.View>
    </Pressable>
  );
}

const styles = StyleSheet.create({
  base: {
    minHeight: 32,
    paddingHorizontal: spacing.md,
    paddingVertical: spacing.xs + 2,
    borderRadius: radii.pill,
    borderWidth: 2,
    alignItems: 'center',
    justifyContent: 'center',
    flexDirection: 'row',
  },
});

// Design tokens — single source of truth for the Marketify visual language.
// Mirrors docs/design.md §1.2 (palette), §1.5 (corners/borders/shadow), and §4 (16px gutter, 12px vertical rhythm).
// Values are `as const` so downstream code gets literal types, not widened string/number.

export const colors = {
  primary: '#EC4899',
  primarySoft: '#FDF2F8',
  primaryDeep: '#831843',

  cta: '#F97316',
  ctaDeep: '#9A3412',

  ink: '#0F172A',
  ink70: '#475569',
  ink40: '#94A3B8',

  surface: '#FFFFFF',
  canvas: '#FFF9F2',
  hairline: '#E5E7EB',

  success: '#16A34A',
  successSoft: '#DCFCE7',
  danger: '#DC2626',
  dangerSoft: '#FEE2E2',
  warning: '#F59E0B',
  warningSoft: '#FEF3C7',
  cancelled: '#6B7280',
  cancelledSoft: '#F3F4F6',

  // Shadow color is always ink per spec §1.2 row "Shadow" — kept as a named alias for palette completeness.
  shadow: '#0F172A',
} as const;

export const spacing = {
  xs: 4,
  sm: 8,
  md: 12,
  base: 16,
  lg: 20,
  xl: 24,
  xxl: 32,
  xxxl: 48,
} as const;

export const radii = {
  card: 12,
  button: 10,
  input: 10,
  image: 8,
  pill: 999,
} as const;

// Neubrutalist hard shadow — solid ink offset (3,3), opacity 1, radius 0.
// RN android uses `elevation`; the hard-shadow look is iOS-primary, android gets a matching elevation hint.
export const shadows = {
  hard: {
    shadowColor: colors.ink,
    shadowOffset: { width: 3, height: 3 },
    shadowOpacity: 1,
    shadowRadius: 0,
    elevation: 4,
  },
  none: {
    shadowColor: 'transparent',
    shadowOffset: { width: 0, height: 0 },
    shadowOpacity: 0,
    shadowRadius: 0,
    elevation: 0,
  },
} as const;

export type ColorToken = keyof typeof colors;
export type SpacingToken = keyof typeof spacing;
export type RadiusToken = keyof typeof radii;
export type ShadowToken = keyof typeof shadows;

